#include <stdint.h>
#include <ctype.h>

int parse_int32(const char *s, int32_t *out)
{
    if (!s || !out)
        return 0;

    while (*s && *s <= ' ')
        s++;
    if (!*s)
        return 0;

    int neg = 0;
    if (*s == '-') {
        neg = 1;
        s++;
    } else if (*s == '+') {
        s++;
    }

    if (!*s || !isdigit((unsigned char)*s))
        return 0;

    int32_t acc = 0;
    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';
        if (neg) {
            if (acc < -214748364 || (acc == -214748364 && digit > 8))
                return 0;
        } else {
            if (acc > 214748364 || (acc == 214748364 && digit > 7))
                return 0;
        }
        acc = acc * 10 + digit;
        s++;
    }

    while (*s && *s <= ' ')
        s++;
    if (*s != '\0')
        return 0;

    if (neg)
        acc = -acc;

    *out = acc;
    return 1;
}

